#include <bits/stdc++.h>
using namespace std;

bool cmp(int a, int b) {
    return a > b;
}

int main() {
    int n, a[1000005];
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    sort(a, a + n, cmp);
    int maxn = 0, cmpn = (n < 32 ? n : 32);
    for (int i = 0; i < cmpn; i++) {
        for (int j = i + 1; j < cmpn; j++) {
            maxn = max(a[i] & a[j], maxn);
        }
    }
    cout << maxn;
    return 0;
}
